            if (e.key == key) {
                entries[index] = e.mapNext;
            } else {
                Entry<V> last;
                do {
                    last = e;
                    e = e.mapNext;
                    if (e == null) {
                        return null;
                    }
                } while (e.key != key);
                last.mapNext = e.mapNext;
            }
            V old = e.getValue();
            mapSize--;
            usedMemory -= e.getMemory();
            if (e.stackNext != null) {
                removeFromStack(e);
