            };
            threads[i] = thread;
        }
        synchronized (TestTriggersConstraints.class) {
            AtomicIntegerArray array = ConcurrentTrigger.array;
            int l = array.length();
            for (int i = 0; i < l; i++) {
                array.set(i, 0);
            }
            for (Thread thread : threads) {
                thread.start();
            }
            for (Thread thread : threads) {
                thread.join();
            }
            for (int i = 0; i < l; i++) {
                assertEquals(1, array.get(i));
            }
        }
        conn.close();
